106→ *
107→ * ```
108→ * fun Flow<DownloadProgress>.completeWhenDone(): Flow<DownloadProgress> =
109→ *     transformWhile { progress ->
110→ *         emit(progress) // always emit progress
111→ *         !progress.isDone() // continue while download is not done
112→ *     }
113→ * ```
114→ */
115→public fun <T, R> Flow<T>.transformWhile(
116→    @BuilderInference transform: suspend FlowCollector<R>.(value: T) -> Boolean
117→): Flow<R> =
118→    safeFlow { // Note: safe flow is used here, because collector is exposed to transform on each operation
119→        // This return is needed to work around a bug in JS BE: KT-39227
120→        return@safeFlow collectWhile { value ->
121→            transform(value)
122→        }
123→    }
124→
125→// Internal building block for non-tailcalling flow-truncating operators
126→internal suspend inline fun <T> Flow<T>.collectWhile(crossinline predicate: suspend (value: T) -> Boolean) {
127→    val collector = object : FlowCollector<T> {
128→        override suspend fun emit(value: T) {
129→            // Note: we are checking predicate first, then throw. If the predicate does suspend (calls emit, for example)
130→            // the the resulting code is never tail-suspending and produces a state-machine
131→            if (!predicate(value)) {
132→                throw AbortFlowException(this)
133→            }
134→        }
135→    }
136→    try {
137→        collect(collector)
138→    } catch (e: AbortFlowException) {
139→        e.checkOwnership(collector)
140→    }
141→}
